use serde::{Deserialize, Serialize};

mod realcompare_reference;

const PI: f64 = 3.1415926535;

fn rc(a: f64, b: f64) -> &'static str {
    realcompare_reference::realcompare(a, b)
}

fn lt(a: f64, b: f64) -> bool {
    rc(a, b) == realcompare_reference::LT
}
fn gt(a: f64, b: f64) -> bool {
    rc(a, b) == realcompare_reference::GT
}
fn eq(a: f64, b: f64) -> bool {
    rc(a, b) == realcompare_reference::EQ
}
fn le(a: f64, b: f64) -> bool {
    let c = rc(a, b);
    c == realcompare_reference::LT || c == realcompare_reference::EQ
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize)]
pub enum Connector {
    #[serde(rename = "NOTUSED")]
    NotUsed,
    #[serde(rename = "ORR")]
    Orr,
    #[serde(rename = "ANDD")]
    Andd,
}

#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct Parameters {
    #[serde(rename = "LENGTH1")]
    pub length1: f64,
    #[serde(rename = "RADIUS1")]
    pub radius1: f64,
    #[serde(rename = "EPSILON")]
    pub epsilon: f64,
    #[serde(rename = "AREA1")]
    pub area1: f64,
    #[serde(rename = "Q_PTS")]
    pub q_pts: usize,
    #[serde(rename = "QUADS")]
    pub quads: usize,
    #[serde(rename = "DIST")]
    pub dist: f64,
    #[serde(rename = "N_PTS")]
    pub n_pts: usize,
    #[serde(rename = "K_PTS")]
    pub k_pts: usize,
    #[serde(rename = "A_PTS")]
    pub a_pts: usize,
    #[serde(rename = "B_PTS")]
    pub b_pts: usize,
    #[serde(rename = "C_PTS")]
    pub c_pts: usize,
    #[serde(rename = "D_PTS")]
    pub d_pts: usize,
    #[serde(rename = "E_PTS")]
    pub e_pts: usize,
    #[serde(rename = "F_PTS")]
    pub f_pts: usize,
    #[serde(rename = "G_PTS")]
    pub g_pts: usize,
    #[serde(rename = "LENGTH2")]
    pub length2: f64,
    #[serde(rename = "RADIUS2")]
    pub radius2: f64,
    #[serde(rename = "AREA2")]
    pub area2: f64,
}

#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct Input {
    pub numpoints: usize,
    pub x: Vec<f64>,
    pub y: Vec<f64>,
    pub parameters: Parameters,
    pub lcm: Vec<Vec<Connector>>,
    pub pum_diag: Vec<bool>,
}

#[derive(Debug, Clone, Serialize)]
pub struct Output {
    pub cmv: Vec<bool>,
    pub pum: Vec<Vec<bool>>,
    pub fuv: Vec<bool>,
    pub launch: bool,
}

#[derive(Debug, Clone, Copy)]
struct Point {
    x: f64,
    y: f64,
}

fn points(input: &Input) -> Vec<Point> {
    input
        .x
        .iter()
        .zip(input.y.iter())
        .map(|(&x, &y)| Point { x, y })
        .collect()
}

fn dist(a: Point, b: Point) -> f64 {
    ((a.x - b.x).powi(2) + (a.y - b.y).powi(2)).sqrt()
}

fn coincide(a: Point, b: Point) -> bool {
    eq(a.x, b.x) && eq(a.y, b.y)
}

fn triangle_area(a: Point, b: Point, c: Point) -> f64 {
    (((b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x)).abs()) / 2.0
}

fn angle_at(p1: Point, v: Point, p3: Point) -> Option<f64> {
    if coincide(p1, v) || coincide(p3, v) {
        return None;
    }
    let v1x = p1.x - v.x;
    let v1y = p1.y - v.y;
    let v2x = p3.x - v.x;
    let v2y = p3.y - v.y;
    let len1 = (v1x * v1x + v1y * v1y).sqrt();
    let len2 = (v2x * v2x + v2y * v2y).sqrt();
    if eq(len1, 0.0) || eq(len2, 0.0) {
        return None;
    }
    let mut cos = (v1x * v2x + v1y * v2y) / (len1 * len2);
    if cos > 1.0 {
        cos = 1.0;
    } else if cos < -1.0 {
        cos = -1.0;
    }
    Some(cos.acos())
}

fn min_enclosing_radius_for_three(a: Point, b: Point, c: Point) -> f64 {
    let d_ab = dist(a, b);
    let d_bc = dist(b, c);
    let d_ac = dist(a, c);

    let (s1, s2, s3) = {
        let mut v = [d_ab, d_bc, d_ac];
        v.sort_by(|p, q| p.partial_cmp(q).unwrap());
        (v[0], v[1], v[2])
    };

    let area = triangle_area(a, b, c);
    if eq(area, 0.0) {
        return s3 / 2.0;
    }

    let s1_2 = s1 * s1;
    let s2_2 = s2 * s2;
    let s3_2 = s3 * s3;
    if le(s1_2 + s2_2, s3_2) {
        return s3 / 2.0;
    }

    (s1 * s2 * s3) / (4.0 * area)
}

fn three_points_in_circle(a: Point, b: Point, c: Point, radius: f64) -> bool {
    le(min_enclosing_radius_for_three(a, b, c), radius)
}

fn quadrant(p: Point) -> u8 {
    let x_ge_0 = !lt(p.x, 0.0);
    let y_ge_0 = !lt(p.y, 0.0);
    let x_lt_0 = lt(p.x, 0.0);
    let y_lt_0 = lt(p.y, 0.0);
    let x_le_0 = x_lt_0 || eq(p.x, 0.0);

    if x_ge_0 && y_ge_0 {
        1
    } else if x_lt_0 && y_ge_0 {
        2
    } else if x_le_0 && y_lt_0 {
        3
    } else {
        4
    }
}

fn lic1(pts: &[Point], p: &Parameters) -> bool {
    for i in 0..pts.len().saturating_sub(1) {
        if gt(dist(pts[i], pts[i + 1]), p.length1) {
            return true;
        }
    }
    false
}

fn lic2(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    for i in 0..pts.len() - 2 {
        if !three_points_in_circle(pts[i], pts[i + 1], pts[i + 2], p.radius1) {
            return true;
        }
    }
    false
}

fn lic3(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    for i in 0..pts.len() - 2 {
        if let Some(a) = angle_at(pts[i], pts[i + 1], pts[i + 2]) {
            if lt(a, PI - p.epsilon) || gt(a, PI + p.epsilon) {
                return true;
            }
        }
    }
    false
}

fn lic4(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    for i in 0..pts.len() - 2 {
        if gt(triangle_area(pts[i], pts[i + 1], pts[i + 2]), p.area1) {
            return true;
        }
    }
    false
}

fn lic5(pts: &[Point], p: &Parameters) -> bool {
    let q = p.q_pts;
    if q < 2 || q > pts.len() {
        return false;
    }
    for start in 0..=pts.len() - q {
        let mut seen = [false; 4];
        for k in 0..q {
            let idx = (quadrant(pts[start + k]) - 1) as usize;
            seen[idx] = true;
        }
        let count = seen.into_iter().filter(|&b| b).count();
        if count > p.quads {
            return true;
        }
    }
    false
}

fn lic6(pts: &[Point]) -> bool {
    for i in 0..pts.len().saturating_sub(1) {
        if lt(pts[i + 1].x - pts[i].x, 0.0) {
            return true;
        }
    }
    false
}

fn point_line_distance(p: Point, a: Point, b: Point) -> f64 {
    let num = ((b.y - a.y) * p.x - (b.x - a.x) * p.y + b.x * a.y - b.y * a.x).abs();
    let den = ((b.y - a.y).powi(2) + (b.x - a.x).powi(2)).sqrt();
    if eq(den, 0.0) {
        0.0
    } else {
        num / den
    }
}

fn lic7(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    let n = p.n_pts;
    if n < 3 || n > pts.len() {
        return false;
    }
    for start in 0..=pts.len() - n {
        let first = pts[start];
        let last = pts[start + n - 1];
        if coincide(first, last) {
            for k in 1..n - 1 {
                if gt(dist(first, pts[start + k]), p.dist) {
                    return true;
                }
            }
        } else {
            for k in 1..n - 1 {
                let d = point_line_distance(pts[start + k], first, last);
                if gt(d, p.dist) {
                    return true;
                }
            }
        }
    }
    false
}

fn lic8(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    let k = p.k_pts;
    for i in 0..pts.len().saturating_sub(k + 1) {
        if gt(dist(pts[i], pts[i + k + 1]), p.length1) {
            return true;
        }
    }
    false
}

fn lic9(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 5 {
        return false;
    }
    let a = p.a_pts;
    let b = p.b_pts;
    let span = a + b + 2;
    for i in 0..pts.len().saturating_sub(span) {
        let p1 = pts[i];
        let p2 = pts[i + a + 1];
        let p3 = pts[i + a + b + 2];
        if !three_points_in_circle(p1, p2, p3, p.radius1) {
            return true;
        }
    }
    false
}

fn lic10(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 5 {
        return false;
    }
    let c = p.c_pts;
    let d = p.d_pts;
    let span = c + d + 2;
    for i in 0..pts.len().saturating_sub(span) {
        let p1 = pts[i];
        let v = pts[i + c + 1];
        let p3 = pts[i + c + d + 2];
        if let Some(a) = angle_at(p1, v, p3) {
            if lt(a, PI - p.epsilon) || gt(a, PI + p.epsilon) {
                return true;
            }
        }
    }
    false
}

fn lic11(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 5 {
        return false;
    }
    let e = p.e_pts;
    let f = p.f_pts;
    let span = e + f + 2;
    for i in 0..pts.len().saturating_sub(span) {
        let p1 = pts[i];
        let p2 = pts[i + e + 1];
        let p3 = pts[i + e + f + 2];
        if gt(triangle_area(p1, p2, p3), p.area1) {
            return true;
        }
    }
    false
}

fn lic12(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    let g = p.g_pts;
    for i in 0..pts.len().saturating_sub(g + 1) {
        if lt(pts[i + g + 1].x - pts[i].x, 0.0) {
            return true;
        }
    }
    false
}

fn lic13(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 3 {
        return false;
    }
    let k = p.k_pts;
    let mut any_gt = false;
    let mut any_lt = false;
    for i in 0..pts.len().saturating_sub(k + 1) {
        let d = dist(pts[i], pts[i + k + 1]);
        if gt(d, p.length1) {
            any_gt = true;
        }
        if lt(d, p.length2) {
            any_lt = true;
        }
        if any_gt && any_lt {
            return true;
        }
    }
    false
}

fn lic14(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 5 {
        return false;
    }
    let a = p.a_pts;
    let b = p.b_pts;
    let span = a + b + 2;
    let mut any_cannot_r1 = false;
    let mut any_can_r2 = false;
    for i in 0..pts.len().saturating_sub(span) {
        let p1 = pts[i];
        let p2 = pts[i + a + 1];
        let p3 = pts[i + a + b + 2];
        if !three_points_in_circle(p1, p2, p3, p.radius1) {
            any_cannot_r1 = true;
        }
        if three_points_in_circle(p1, p2, p3, p.radius2) {
            any_can_r2 = true;
        }
        if any_cannot_r1 && any_can_r2 {
            return true;
        }
    }
    false
}

fn lic15(pts: &[Point], p: &Parameters) -> bool {
    if pts.len() < 5 {
        return false;
    }
    let e = p.e_pts;
    let f = p.f_pts;
    let span = e + f + 2;
    let mut any_gt = false;
    let mut any_lt = false;
    for i in 0..pts.len().saturating_sub(span) {
        let p1 = pts[i];
        let p2 = pts[i + e + 1];
        let p3 = pts[i + e + f + 2];
        let area = triangle_area(p1, p2, p3);
        if gt(area, p.area1) {
            any_gt = true;
        }
        if lt(area, p.area2) {
            any_lt = true;
        }
        if any_gt && any_lt {
            return true;
        }
    }
    false
}

fn compute_cmv(pts: &[Point], p: &Parameters) -> [bool; 15] {
    [
        lic1(pts, p),
        lic2(pts, p),
        lic3(pts, p),
        lic4(pts, p),
        lic5(pts, p),
        lic6(pts),
        lic7(pts, p),
        lic8(pts, p),
        lic9(pts, p),
        lic10(pts, p),
        lic11(pts, p),
        lic12(pts, p),
        lic13(pts, p),
        lic14(pts, p),
        lic15(pts, p),
    ]
}

pub fn decide(input: &Input) -> Output {
    let pts = points(input);
    let cmv = compute_cmv(&pts, &input.parameters);

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            pum[i][j] = match input.lcm[i][j] {
                Connector::NotUsed => true,
                Connector::Andd => cmv[i] && cmv[j],
                Connector::Orr => cmv[i] || cmv[j],
            };
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&v| v);
        }
    }

    let launch = fuv.iter().all(|&v| v);

    Output {
        cmv: cmv.into_iter().collect(),
        pum,
        fuv,
        launch,
    }
}
